import { UAParser } from 'ua-parser-js';
import { getReq } from '@meli/server-context';

import { DEVICE_MODEL_HEADER, USER_AGENT } from '../constants';

export function getDeviceModel() {
  const { headers } = getReq();
  const model = headers[DEVICE_MODEL_HEADER];

  if (typeof model === 'string' && model) {
    return model;
  }

  return UAParser(headers[USER_AGENT]).device.model;
}
